import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { EmailManagementCreateComponent } from './email-management-create/email-management-create.component';
import { EmailManagementComponent } from './email-management/email-management.component';

const routes: Routes = [
  {
    path:"",
    component:EmailManagementComponent
  },
  {
    path:"create",
    component:EmailManagementCreateComponent
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class EmailManagementRoutingModule { }
