import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { AppConstants } from '../config/app.constant';
import { BehaviorSubject, Observable } from 'rxjs';
import { EmailDetails } from '../models/EmailDetails';



export const API_URL = AppConstants.baseURL;
@Injectable({
  providedIn: 'root'
})

export class AccountBlockingServiceService {


  constructor(private http: HttpClient) { }
  private paramSource = new BehaviorSubject({});
    getNavParam = this.paramSource.asObservable();
    
     sendNavParam(params: object) {
      this.paramSource.next(params)
    }
  // new module
  emailMaintenance(ac_type: string, inputBy: string, tobackend) {
    //console.log("from apiservice ", tobackend, ac_type);
    return this.http.post<any>(`${API_URL}/emailMaintenence/createEmailNotif/${ac_type}/${inputBy}`, tobackend)
  }
  getAllEmail(): Observable<any> {
    return this.http.get<any>(`${API_URL}/emailMaintenence/summary`);
  }
  sendAccType(emailType: string) {
    return this.http.get<any[]>(`${API_URL}/emailMaintenence/getDetailsData/${emailType}`)
  }
  
  //audit log --methods
  onClickOfAuthOfEmailManagement(emailType: string, loginUSer: string) {
    //console.log("type:",emailType)
    //console.log("loginUSer",loginUSer)
    return this.http.get(`${API_URL}/emailMaintenence/verify/${emailType}/${loginUSer}`)
  }
  onclickOfReopenOfEamilManagement(emailType: string, loginUSer: string) {
    return this.http.get(`${API_URL}/emailMaintenence/reopen/${emailType}/${loginUSer}`)
  }
  onclickOfCloseOfEmailManagement(emailType: string, loginUSer: string) {
    return this.http.get(`${API_URL}/emailMaintenence/close/${emailType}/${loginUSer}`)
  }
  onclickOfEditOfEmailManagement(ac_type: string, inputBy: string, tobackend) {
    return this.http.post(`${API_URL}/emailMaintenence/modifyEmailNotif/${ac_type}/${inputBy}`, tobackend)
  }
  onclickOfDeleteOfEmailManagement(account_type: string, loginUser: string) {
    console.log(account_type, loginUser);
    return this.http.delete(`${API_URL}/emailMaintenence/delete/${account_type}/${loginUser}`)
  }
  deleteingParticluarRow(emailType: string, loginUser: string, id: any) {
    return this.http.delete(`${API_URL}/emailMaintenence/deleteById/${emailType}/${loginUser}/${id}`)
  }
}
